using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Preserve EF8 discriminator JSON property name (was "Discriminator", now defaults to "$type")
            b.HasDiscriminator<string>("Discriminator");
            // Preserve EF8 id format "Blog|<key>" (EF9 defaults to key-only)
            b.HasDiscriminatorInJsonId();
            // Preserve EF8 shadow __id property (EF9 maps key directly to JSON "id")
            b.HasShadowId();
        });
    }
}
